# Worked focus: http-py-sensitive-field-forwarding — Strip or deliberately reissue authorization, cookies, origin-sensitive fields, and bodies when authority changes. Demonstrate the result through Python 3.14 urllib, http.client, ssl, typed protocols, and fixture transports.
def worked_http_py_redirects_policy_4(status: int, same_origin: bool, hop: int, has_credentials: bool) -> dict[str, object]:
    assert isinstance(status, int) and isinstance(hop, int)
    preserve_method = status in {307, 308}
    if not 0 <= hop < 8:
        return {"follow": False, "preserve_method": preserve_method, "forward_credentials": False}
    redirect_status = 300 <= status < 400
    return {"follow": redirect_status, "preserve_method": preserve_method, "forward_credentials": redirect_status and same_origin and has_credentials}

